    const N = parseInt(next(it), 10);
    const M = parseInt(next(it), 10);
    const tasks: string[] = [];
    for (let i = 0; i < N; i++) {
        tasks.push(next(it));
    }
    const adj = new Map<string, string[]>();
    const inDeg = new Map<string, number>();
